// Error handler: Log and notify on workflow failures
const error = $input.first().json;
const workflowName = error.workflow?.name || 'Unknown Workflow';
const errorMessage = error.error?.message || error.message || 'Unknown error';
const errorStack = error.error?.stack || error.stack || '';
const nodeExecuted = error.node?.name || 'Unknown Node';
const executionId = error.execution?.id || 'Unknown';

const timestamp = new Date().toISOString();
const severity = errorMessage.toLowerCase().includes('rate limit') ? 'warning' : 'error';

console.error(`[${timestamp}] Workflow Error in ${workflowName}`);
console.error(`  Node: ${nodeExecuted}`);
console.error(`  Error: ${errorMessage}`);
console.error(`  Execution ID: ${executionId}`);

return [{
  json: {
    workflowName,
    errorMessage,
    errorStack,
    nodeExecuted,
    executionId,
    timestamp,
    severity,
    handled: true
  }
}];

